#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char top[3], bottom[3];
        scanf("%s %s", top, bottom);
        int found = 0;
        for (int i = 0; i < 3; i++) {
            for (int j = 0; j < 3; j++) {
                for (int k = 0; k < 3; k++) {
                    if (i != j && j != k && k != i) {
                        char a, b, c;
                        a = (top[i] == 'b' || bottom[i] == 'b') ? 'b' : (top[i] == 'o' || bottom[i] == 'o') ? 'o' : 'b';
                        b = (top[j] == 'o' || bottom[j] == 'o') ? 'o' : (top[j] == 'b' || bottom[j] == 'b') ? 'b' : 'o';
                        c = (top[k] == 'b' || bottom[k] == 'b') ? 'b' : (top[k] == 'o' || bottom[k] == 'o') ? 'o' : 'b';
                        if (a == 'b' && b == 'o' && c == 'b') {
                            found = 1;
                            break;
                        }
                    }
                }
                if (found) break;
            }
            if (found) break;
        }
        if (found) printf("yes\n");
        else printf("no\n");
    }
    return 0;
}

